// ============================================================
// рҹ§  PRE-PROCESADOR v3 вҖ” CO CORTO
// ============================================================

const config = $('вҡҷпёҸ CONFIGURAR TODO AQUГҚ').item.json;
const body = $('When Executed by Recibidor').item.json.body || {};
const labels = body.labels || [];
const customAttrs = body.custom_attributes || body.meta?.sender?.custom_attributes || {};
const mensajeOriginal = (config.cliente_mensaje || '').toString();
const msgLower = mensajeOriginal.toLowerCase().trim();

// ============================================================
// 1пёҸвғЈ DETERMINAR PRECIO ACTUAL
// ============================================================
const estadoRmk = customAttrs.estado_rmk || '';
let precioBase = [PRECIO_BASE];
if (estadoRmk === 'rmk_15m_[CATEGORIA_PRODUCTO]') precioBase = [PRECIO_RMK_15M];
else if (estadoRmk === 'rmk_60m_[CATEGORIA_PRODUCTO]') precioBase = [PRECIO_RMK_60M];
else if (estadoRmk === 'rmk_180m_[CATEGORIA_PRODUCTO]') precioBase = [PRECIO_RMK_180M];

// рҹ”‘ Regex para COP: detecta $7.000, 8mil, 10k, 15,000, etc.
const matchPrecio = msgLower.match(/(\$?\s*)(7|8|9|10|12|15|18|20|22)([\.,]?000|\s*mil|k)/);
let precioMencionadoPorCliente = null;
if (matchPrecio) {
  const num = parseInt(matchPrecio[2]);
  if (num >= [PISO_REGATEO_MILES] && num <= 22) {
    precioMencionadoPorCliente = num * 1000;
  }
}

const precioCotizar = precioMencionadoPorCliente || precioBase;
const precioCombo = precioCotizar + [PRECIO_ADICIONAL_OB];

// ============================================================
// 2пёҸвғЈ ESTADO DEL CLIENTE
// ============================================================
const yaCompro = labels.includes('comprador');
const tocoMetodoPago = labels.includes('metodo_pago');
const tieneOBSi = labels.includes('ob_si');

let modoCliente = 'PROSPECTO';
if (yaCompro) modoCliente = 'COMPRADOR';
else if (tocoMetodoPago) modoCliente = 'PENDIENTE_PAGO';

// ============================================================
// 3пёҸвғЈ DETECTAR CATEGORГҚA
// ============================================================
let categoria = 'OTRO';
const tieneAlguna = (palabras) => palabras.some(p => msgLower.includes(p));

if (tieneAlguna(['cuГЎnto', 'cuanto', 'precio', 'cuesta', 'vale', 'pagar', 'costo']) || matchPrecio !== null) {
  categoria = 'PRECIO';
}
else if (tieneAlguna(['cuГЎndo llega', 'cuando llega', 'cuГЎndo recibo', 'cuando recibo',
                      'cuГЎnto tarda', 'cuanto tarda', 'tiempo de entrega', 'inmediato', 'me llega'])) {
  categoria = 'ENTREGA';
}
else if (tieneAlguna(['garantГӯa', 'garantia', 'cuГЎnto dura', 'caduca', 'expira', 'mensualidad'])) {
  categoria = 'GARANTIA';
}
else if (tieneAlguna(['virtual', 'presencial', 'fГӯsico', 'fisico', 'quГ© incluye', 'que incluye',
                      'quГ© viene', 'que viene', 'quГ© es', 'que es'])) {
  categoria = 'CONTENIDO';
}
else if (tieneAlguna(['cГіmo pago', 'como pago', 'mГ©todos de pago', 'metodos de pago', 'formas de pago',
                      'nequi', 'daviplata', 'bre-b', 'breb', 'donde pago', 'dГіnde pago'])) {
  categoria = 'METODOS_PAGO';
}
