// ============================================================
// CLASIFICADOR вҖ” versiГіn Order Bump SГҡPER PERMISIVA (CO)
// ============================================================
const MODO_TESTING = true;

const input = $input.first().json;
const body = input.body || {};
const messages = body.messages || [];
const lastMsg = messages[messages.length - 1] || {};
const labels = body.labels || [];

// ===== ВҝEs imagen? =====
const esImagen = (lastMsg.content_type === 'image') ||
                 (lastMsg.attachments && lastMsg.attachments.length > 0 && lastMsg.attachments[0].file_type === 'image');

// ===== ВҝEs respuesta a botГіn? вҖ” DetecciГіn robusta =====
let botonValue = null;
const contenidoTexto = (lastMsg.content || '').trim();

function normalizar(texto) {
  return texto
    .replace(/[\u{1F300}-\u{1F9FF}]/gu, '')
    .replace(/[\u{2600}-\u{27BF}]/gu, '')
    .replace(/[\u{1F000}-\u{1FFFF}]/gu, '')
    .replace(/\uFE0F/g, '')
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();
}

// FORMATO A: submitted_values
if (lastMsg.content_attributes &&
    lastMsg.content_attributes.submitted_values &&
    lastMsg.content_attributes.submitted_values.length > 0) {
  botonValue = lastMsg.content_attributes.submitted_values[0].value;
}
// FORMATO B: content directo
else if (contenidoTexto === 'ob_si' || contenidoTexto === 'ob_no' || contenidoTexto.startsWith('pago_')) {
  botonValue = contenidoTexto;
}
// FORMATO C: matching por contenido normalizado
else {
  const normalizado = normalizar(contenidoTexto);

  // рҹӣ’ Order Bump (PERMISIVA)
  if (normalizado === 'si' || normalizado === 'sГӯ' || normalizado === 'yes') {
    botonValue = 'ob_si';
  } else if (normalizado === 'no') {
    botonValue = 'ob_no';
  }
  // рҹ’і MГ©todos de pago CO
  else if (normalizado.includes('nequi')) {
    botonValue = 'pago_nequi';
  } else if (normalizado.includes('daviplata')) {
    botonValue = 'pago_daviplata';
  } else if (normalizado.includes('bre-b') || normalizado.includes('breb') || normalizado.includes('llave')) {
    botonValue = 'pago_breb';
  }
  // Remarketing combo button
  else if (normalizado.includes('no mГЎs') || normalizado.includes('no mas')) {
    botonValue = 'no_mas_rmk';
  }
  // Detectar "cГіmo pago" / "dГіnde pago" como intenciГіn de pago
  else if (normalizado.includes('cГіmo pago') || normalizado.includes('como pago') || 
           normalizado.includes('dГіnde pago') || normalizado.includes('donde pago') ||
           normalizado.includes('mГ©todos de pago') || normalizado.includes('formas de pago')) {
    // No es botГіn, dejar que Carlos responda con los mГ©todos
  }
}

const esBoton = botonValue !== null;

// ===== ВҝEs nuevo lead? =====
const esNuevo = MODO_TESTING
  ? !labels.includes('bienvenido')
  : input.is_new_attribution === true;

// ===== ClasificaciГіn final =====
let tipoMensaje = 'TEXTO_LIBRE';
if (esImagen) tipoMensaje = 'IMAGEN';
else if (esBoton) tipoMensaje = 'BOTON';
else if (esNuevo) tipoMensaje = 'AD';

return {
  json: {
    tipo_mensaje: tipoMensaje,
    boton_value: botonValue,
    es_imagen: esImagen,
    contenido_texto_recibido: contenidoTexto,
    contenido_normalizado: normalizar(contenidoTexto),
    es_nuevo: esNuevo,
    labels_actuales: labels,
    imagen_url: esImagen && lastMsg.attachments ? lastMsg.attachments[0].data_url : null
  }
};

